SELECT
    a.pay_merchant_id as merchantId,
    u.name as merchantName,

    count(distinct a.user_id) as peopleNum,

    COUNT(*) AS orderNum,

    SUM(CASE WHEN order_status = 1 THEN 1 ELSE 0 END) AS successOrderNum,

    ifnull(sum(a.amount), 0.0000) as pullOrderAmount,

    ifnull(sum(a.amount), 0.0000) as rechargeTotalAmount,

    ifnull(SUM(CASE WHEN order_status = 1 THEN total_amount ELSE 0 END), 0.0000) AS successAmount,

    case
    when count(*) = 0 then 0
    else round(sum(case when a.order_status = 1 then 1 else 0 end) * 100.0 / count(*), 2)
    end as successRate

FROM t_order_amount a
left join t_merchant_pay u on u.id = a.pay_merchant_id

    and a.pay_merchant_id = #{merchantId}
    and a.currency_id = #{currencyId}
    and a.pay_type_id = #{payTypeId}
    and a.pay_channel_id = #{payChannelId}

        and (


                a.create_time between #{item,jdbcType=VARCHAR}


                and #{item,jdbcType=VARCHAR}


        )


        and (


                a.pay_time between #{item,jdbcType=VARCHAR}


                and #{item,jdbcType=VARCHAR}


        )


GROUP BY a.pay_merchant_id;

